class Bad {
    fun check(input: String, expected: String): Boolean {
        return input.toLowerCase().equals(expected)
    }
}

class Bad {
    fun check(input: String, expected: String): Boolean {
        return input.toUpperCase().equals(expected)
    }
}

class Good {
    fun check(input: String, expected: String): Boolean {
        return input.equals(expected, ignoreCase = true)
    }
}

class Good {
    fun lower(s: String): String {
        return s.toLowerCase()
    }
}
